// Helper: cálculo de estoque/vendas/distribuições
function obterTotalVendasProduto(produto) {
    if (!produto) return 0;
    // Verificar se há registros detalhados para este produto específico (fonte de verdade)
    const registrosDesteProduto = Array.isArray(estoque.registroVendas)
        ? estoque.registroVendas.filter(v => {
            if (Array.isArray(v.items) && v.items.length) {
                return v.items.some(it =>
                    Number(it.produtoId) === Number(produto.id) ||
                    it.produto === produto.nome ||
                    it.produtoNome === produto.nome
                );
            }
            return Number(v.produtoId) === Number(produto.id) || v.produtoNome === produto.nome;
        })
        : [];
    if (registrosDesteProduto.length > 0) {
        return registrosDesteProduto.reduce((sum, v) => {
            if (Array.isArray(v.items) && v.items.length) {
                return sum + v.items.reduce((s, it) => {
                    if (Number(it.produtoId) === Number(produto.id) || (it.produto === produto.nome) || (it.produtoNome === produto.nome)) return s + (Number(it.quantidade) || 0);
                    return s;
                }, 0);
            }
            if (Number(v.produtoId) === Number(produto.id) || v.produtoNome === produto.nome) return sum + (Number(v.quantidade) || 0);
            return sum;
        }, 0);
    }
    // Fallback para agregado em produto.vendas quando não há registros para este produto
    if (!produto.vendas) return 0;
    return Object.keys(produto.vendas).reduce((s, k) => s + (Number(produto.vendas[k]) || 0), 0);
}

function obterDistribuicaoTotalExcluindoImbel(produto) {
    if (!produto) return 0;
    // Verificar se há registros de distribuição para este produto específico (fonte de verdade)
    const registrosDesteProduto = Array.isArray(estoque.registroDistribuicao)
        ? estoque.registroDistribuicao.filter(d =>
            Number(d.produtoId) === Number(produto.id) ||
            (d.produtoNome && d.produtoNome === produto.nome)
        )
        : [];
    if (registrosDesteProduto.length > 0) {
        return registrosDesteProduto.reduce((s, d) => {
            try {
                const rep = (d.representante || '').toString().toUpperCase();
                if (rep === 'IMBEL') return s;
                return s + (Number(d.quantidade) || 0);
            } catch (e) {
                console.warn('obterDistribuicaoTotalExcluindoImbel: erro ao processar registro', e);
                return s;
            }
        }, 0);
    }
    // Fallback para o objeto produto.distribuicao (legado) quando não há registros para este produto
    if (!produto.distribuicao) return 0;
    return Object.keys(produto.distribuicao).reduce((s, k) => {
        if ((k || '').toUpperCase() === 'IMBEL') return s;
        return s + (Number(produto.distribuicao[k]) || 0);
    }, 0);
}

function calcularSaldoConsolidado(produto) {
    if (!produto) return 0;
    const estoqueConc = Number(produto.estoqueConsolidado || 0);
    const vendas = obterTotalVendasProduto(produto);
    return estoqueConc - vendas;
}

function calcularImbelDisponivel(produto) {
    // Retornar o saldo disponível na IMBEL considerando:
    // estoque consolidado, distribuições (exceto IMBEL), devoluções para IMBEL
    // e apenas as vendas atribuídas à IMBEL — mantém coerência com `obterMetricasImbelProduto`.
    try {
        if (!produto) return 0;
        const met = obterMetricasImbelProduto(produto);
        return Number(met.imbelSaldo || 0);
    } catch (e) {
        return 0;
    }
}

// Calcula estoque disponível na IMBEL baseado exclusivamente em registros
function calcularEstoqueIMBEL(nomeProduto) {
    if (!nomeProduto) return 0;
    const produtos = estoque.produtos || [];
    const produto = produtos.find(p => {
        try {
            if (!p || !p.nome) return false;
            return p.nome.toString().toUpperCase() === nomeProduto.toString().toUpperCase();
        } catch (e) { return false; }
    });
    if (!produto) return 0;

    const estoqueTotal = Number(produto.estoqueConsolidado || produto.estoqueTotal || produto.estoque || 0);

    const totalDistribuido = (estoque.registroDistribuicao || []).reduce((sum, d) => {
        try {
            const match = (Number(d.produtoId) === Number(produto.id)) || ((d.produtoNome || '').toString().toUpperCase() === produto.nome.toString().toUpperCase());
            if (!match) return sum;
            const rep = (d.representante || '').toString().toUpperCase();
            if (rep === 'IMBEL') return sum; // não descontar distribuições para IMBEL
            return sum + (Number(d.quantidade) || 0);
        } catch (e) { return sum; }
    }, 0);

    const totalDevolvido = (estoque.registroDevolucoes || []).reduce((sum, d) => {
        try {
            const match = (Number(d.produtoId) === Number(produto.id)) || ((d.produtoNome || '').toString().toUpperCase() === produto.nome.toString().toUpperCase());
            if (!match) return sum;
            const destino = (d.destino || '').toString().toUpperCase();
            if (destino === 'IMBEL') return sum + (Number(d.quantidade) || 0);
        } catch (e) {
            console.warn('calcularEstoqueIMBEL: erro ao processar devolução', e);
        }
        return sum;
    }, 0);

    return estoqueTotal - totalDistribuido + totalDevolvido;
}

function obterMetricasImbelProduto(produto) {
    if (!produto) {
        return { estoqueTotal: 0, imbelDisp: 0, imbelVenda: 0, imbelSaldo: 0 };
    }

    const produtoId = produto.id;
    const estoqueTotal = Number(
        (produto.estoqueConsolidado ?? produto.estoqueTotal ?? produto.estoque ?? produto.qtdTotal ?? produto.estoqueInicial) || 0
    );

    const distPorRep = {};
    (estoque.registroDistribuicao || []).forEach(d => {
        try {
            if (Number(d.produtoId) === Number(produtoId) || (d.produtoNome && d.produtoNome === produto.nome)) {
                const r = (d.representante || '').toString().toUpperCase();
                distPorRep[r] = (distPorRep[r] || 0) + (Number(d.quantidade) || 0);
            }
        } catch (e) {
            console.warn('obterMetricasImbelProduto: erro ao processar distribuição', e);
        }
    });
    const totalDistribuido = Object.values(distPorRep).reduce((s, v) => s + v, 0);

    let totalDevolvidoParaImbel = 0;
    (estoque.registroDevolucoes || []).forEach(d => {
        try {
            if (Number(d.produtoId) === Number(produtoId) || (d.produtoNome && d.produtoNome === produto.nome)) {
                const destino = (d.destino || '').toString().toUpperCase();
                if (destino === 'IMBEL') totalDevolvidoParaImbel += (Number(d.quantidade) || 0);
            }
        } catch (e) {
            console.warn('obterMetricasImbelProduto: erro ao processar devolução', e);
        }
    });

    const vendasPorRep = {};
    (estoque.registroVendas || []).forEach(v => {
        if (v.cancelado) return;
        try {
            const rep = (v.representante || '').toString().toUpperCase();
            if (Array.isArray(v.items) && v.items.length) {
                v.items.forEach(it => {
                    if (Number(it.produtoId) === Number(produtoId) || (it.produto === produto.nome) || (it.produtoNome === produto.nome)) {
                        vendasPorRep[rep] = (vendasPorRep[rep] || 0) + (Number(it.quantidade) || 0);
                    }
                });
            } else if (Number(v.produtoId) === Number(produtoId) || (v.produtoNome === produto.nome)) {
                vendasPorRep[rep] = (vendasPorRep[rep] || 0) + (Number(v.quantidade) || 0);
            }
        } catch (e) {
            console.warn('obterMetricasImbelProduto: erro ao processar venda', e);
        }
    });

    const totalVendasProduto = Object.values(vendasPorRep).reduce((s, v) => s + v, 0);
    const consolidadoDisp = estoqueTotal;
    const consolidadoVenda = totalVendasProduto;
    const consolidadoSaldo = consolidadoDisp - consolidadoVenda;

    const imbelDisp = estoqueTotal - totalDistribuido + totalDevolvidoParaImbel;
    const imbelVenda = Number(vendasPorRep['IMBEL'] || 0);
    const imbelSaldo = imbelDisp - imbelVenda;

    return {
        estoqueTotal,
        imbelDisp,
        imbelVenda,
        imbelSaldo,
        consolidadoDisp,
        consolidadoVenda,
        consolidadoSaldo
    };
}

// Verifica se um item/registro de venda corresponde a um produto (por ID numérico ou nome)
// Necessário porque registros históricos podem ter produtoId antigo (ex: 11) enquanto produto.id é novo (ex: 1779112654305)
function vendaItemMatchProduto(item, produto) {
    if (!item || !produto) return false;
    if (Number(item.produtoId) === Number(produto.id)) return true;
    if (item.produtoNome && produto.nome && item.produtoNome.trim().toLowerCase() === produto.nome.trim().toLowerCase()) return true;
    return false;
}
function vendaMatchProduto(v, produto) {
    if (!v || !produto) return false;
    if (Array.isArray(v.items) && v.items.length) return v.items.some(i => vendaItemMatchProduto(i, produto));
    if (Number(v.produtoId) === Number(produto.id)) return true;
    if (v.produtoNome && produto.nome && v.produtoNome.trim().toLowerCase() === produto.nome.trim().toLowerCase()) return true;
    return false;
}
function vendaItemQtdParaProduto(v, produto) {
    if (!v || !produto) return 0;
    if (Array.isArray(v.items) && v.items.length) {
        const it = v.items.find(i => vendaItemMatchProduto(i, produto));
        return it ? (Number(it.quantidade) || 0) : 0;
    }
    if (Number(v.produtoId) === Number(produto.id)) return Number(v.quantidade) || 0;
    if (v.produtoNome && produto.nome && v.produtoNome.trim().toLowerCase() === produto.nome.trim().toLowerCase()) return Number(v.quantidade) || 0;
    return 0;
}

// Reconstrói o objeto `produto.distribuicao` a partir dos registros de distribuição e devolução
function reconstruirDistribuicaoAPartirDeRegistros() {
    if (!Array.isArray(estoque.produtos)) return;
    // Inicializar chaves
    estoque.produtos.forEach(p => {
        try {
            if (!p.distribuicao) p.distribuicao = {};
            (estoque.representantes || []).forEach(r => { p.distribuicao[r] = 0; });
            // manter IMBEL sempre 0 (é derivado)
            p.distribuicao.IMBEL = 0;
        } catch (e) {
            console.warn('reconstruirDistribuicaoAPartirDeRegistros: erro ao inicializar produto', e);
        }
    });

    // Somar todas as distribuições
    (estoque.registroDistribuicao || []).forEach(d => {
        try {
            const prod = estoque.produtos.find(p => Number(p.id) === Number(d.produtoId) || (d.produtoNome && p.nome === d.produtoNome));
            if (!prod) return;
            const rep = (d.representante || '').toString().toUpperCase();
            if (!rep) return;
            prod.distribuicao[rep] = (prod.distribuicao[rep] || 0) + (Number(d.quantidade) || 0);
        } catch (e) {
            console.warn('reconstruirDistribuicaoAPartirDeRegistros: erro ao processar distribuição', e);
        }
    });

    // Aplicar devoluções: subtrair do origem, somar para destino quando não for IMBEL
    (estoque.registroDevolucoes || []).forEach(dev => {
        try {
            const prod = estoque.produtos.find(p => Number(p.id) === Number(dev.produtoId) || (dev.produtoNome && p.nome === dev.produtoNome));
            if (!prod) return;
            const origem = (dev.origem || '').toString().toUpperCase();
            const destino = (dev.destino || '').toString().toUpperCase();
            prod.distribuicao[origem] = Math.max(0, (prod.distribuicao[origem] || 0) - (Number(dev.quantidade) || 0));
            if (destino && destino !== 'IMBEL') {
                prod.distribuicao[destino] = (prod.distribuicao[destino] || 0) + (Number(dev.quantidade) || 0);
            }
        } catch (e) {
            console.warn('reconstruirDistribuicaoAPartirDeRegistros: erro ao processar devolução', e);
        }
    });
}

// Reconstrói o objeto `produto.vendas` a partir dos registros de venda (exclui canceladas)
function reconstruirVendasAPartirDeRegistros() {
    if (!Array.isArray(estoque.produtos)) return;
    estoque.produtos.forEach(p => {
        p.vendas = {};
        (estoque.representantes || []).forEach(r => { p.vendas[r] = 0; });
    });
    (estoque.registroVendas || []).forEach(v => {
        try {
            if (v.cancelado) return;
            const rep = (v.representante || '').toString().toUpperCase();
            if (!rep) return;
            if (Array.isArray(v.items) && v.items.length) {
                v.items.forEach(it => {
                    const prod = estoque.produtos.find(p => Number(p.id) === Number(it.produtoId) || (it.produtoNome && p.nome && it.produtoNome.trim().toLowerCase() === p.nome.trim().toLowerCase()));
                    if (!prod) return;
                    if (!prod.vendas) prod.vendas = {};
                    prod.vendas[rep] = (prod.vendas[rep] || 0) + (Number(it.quantidade) || 0);
                });
            } else if (v.produtoId || v.produtoNome) {
                const prod = estoque.produtos.find(p => Number(p.id) === Number(v.produtoId) || (v.produtoNome && p.nome && v.produtoNome.trim().toLowerCase() === p.nome.trim().toLowerCase()));
                if (!prod) return;
                if (!prod.vendas) prod.vendas = {};
                prod.vendas[rep] = (prod.vendas[rep] || 0) + (Number(v.quantidade) || 0);
            }
        } catch (e) {
            console.warn('reconstruirVendasAPartirDeRegistros: erro ao processar venda', e);
        }
    });
}

// Migração única: normaliza produtoId antigo nos registros históricos para o ID atual do produto (por nome)
// Chame normalizarProdutoIdsNosRegistros() no console para executar manualmente, ou chame em carregarDados
function normalizarProdutoIdsNosRegistros() {
    let totalAlterados = 0;
    const colecoes = [
        { arr: estoque.registroVendas || [], tipo: 'venda' },
        { arr: estoque.registroDistribuicao || [], tipo: 'distribuicao' },
        { arr: estoque.registroDevolucoes || [], tipo: 'devolucao' },
    ];
    colecoes.forEach(({ arr, tipo }) => {
        arr.forEach(reg => {
            // Registros multi-item (vendas com items[])
            if (Array.isArray(reg.items)) {
                reg.items.forEach(it => {
                    const prodAtual = (estoque.produtos || []).find(p => Number(p.id) === Number(it.produtoId));
                    if (prodAtual) return; // ID já correto
                    const porNome = it.produtoNome && (estoque.produtos || []).find(p => p.nome && p.nome.trim().toLowerCase() === it.produtoNome.trim().toLowerCase());
                    if (porNome && porNome.id !== it.produtoId) {
                        it.produtoId = porNome.id;
                        totalAlterados++;
                    }
                });
            }
            // Registros de campo único
            if (reg.produtoId !== undefined) {
                const prodAtual = (estoque.produtos || []).find(p => Number(p.id) === Number(reg.produtoId));
                if (!prodAtual) {
                    const porNome = reg.produtoNome && (estoque.produtos || []).find(p => p.nome && p.nome.trim().toLowerCase() === reg.produtoNome.trim().toLowerCase());
                    if (porNome && porNome.id !== reg.produtoId) {
                        reg.produtoId = porNome.id;
                        totalAlterados++;
                    }
                }
            }
        });
    });
    if (totalAlterados > 0) {
        salvarDados();
        console.log(`normalizarProdutoIdsNosRegistros: ${totalAlterados} registro(s) corrigido(s) e salvos.`);
    } else {
        console.log('normalizarProdutoIdsNosRegistros: nenhuma inconsistência encontrada.');
    }
    return totalAlterados;
}

// Função de diagnóstico disponível no console para inspecionar um produto rapidamente
function diagnosticarProduto(produtoId) {
    try {
        const p = estoque.produtos.find(x => Number(x.id) === Number(produtoId) || String(x.id) === String(produtoId));
        if (!p) { console.warn('Produto não encontrado:', produtoId); return null; }
        const estoqueConsolidado = Number(p.estoqueConsolidado) || 0;
        const totalDistribuido = (estoque.registroDistribuicao || []).reduce((s, d) => {
            try {
                if (Number(d.produtoId) === Number(p.id) || (d.produtoNome && d.produtoNome === p.nome)) return s + (Number(d.quantidade) || 0);
            } catch (e) {
                console.warn('diagnosticarProduto: erro ao processar distribuição', e);
            }
            return s;
        }, 0);
        const totalDevolvidoParaImbel = (estoque.registroDevolucoes || []).reduce((s, d) => {
            try {
                if ((Number(d.produtoId) === Number(p.id) || (d.produtoNome && d.produtoNome === p.nome)) && ((d.destino || '').toString().toUpperCase() === 'IMBEL')) return s + (Number(d.quantidade) || 0);
            } catch (e) {
                console.warn('diagnosticarProduto: erro ao processar devolução', e);
            }
            return s;
        }, 0);
        const totalVendas = obterTotalVendasProduto(p);
        const imbelDisponivel = estoqueConsolidado - totalDistribuido + totalDevolvidoParaImbel;
        const distribuicaoPorRep = {};
        (estoque.representantes || []).forEach(r => { distribuicaoPorRep[r] = p.distribuicao ? (p.distribuicao[r] || 0) : 0; });
        const result = { produtoId: p.id, nome: p.nome, estoqueConsolidado, totalDistribuido, totalDevolvidoParaImbel, totalVendas, imbelDisponivel, distribuicaoPorRep };
        console.debug('Diagnóstico do produto:', result);
        return result;
    } catch (e) { console.error('Erro no diagnóstico:', e); return null; }
}
window.diagnosticarProduto = diagnosticarProduto;

// Atalho por nome (útil para console): `diagnosticarProdutoPorNome("NOME DO PRODUTO")`
function diagnosticarProdutoPorNome(nome) {
    if (!nome) return null;
    const p = (estoque.produtos || []).find(x => (x.nome || '').toString().toUpperCase() === nome.toString().toUpperCase());
    if (!p) { console.warn('Produto não encontrado por nome:', nome); return null; }
    return diagnosticarProduto(p.id);
}
window.diagnosticarProdutoPorNome = diagnosticarProdutoPorNome;

// Diagnóstico específico: mostra tudo sobre um produto para um representante
function diagRep(nomeProduto, rep) {
    const p = (estoque.produtos || []).find(x => (x.nome||'').toUpperCase().includes((nomeProduto||'').toUpperCase()));
    if (!p) { console.error('Produto não encontrado:', nomeProduto); return; }
    const repUpper = (rep||'ISA').toUpperCase();

    console.group(`=== Diagnóstico: ${p.nome} / ${rep} ===`);
    console.log('produto.id:', p.id, '| tipo:', typeof p.id);

    // --- distribuicao ---
    console.group('distribuicao');
    console.log('todas as chaves e valores:', JSON.stringify(p.distribuicao));
    const distribKey = p.distribuicao ? Object.keys(p.distribuicao).find(k => k.toUpperCase() === repUpper) : null;
    console.log('chave encontrada para', rep, ':', distribKey, '→', distribKey ? p.distribuicao[distribKey] : 'NÃO ENCONTRADA');
    const regDist = (estoque.registroDistribuicao||[]).filter(d => Number(d.produtoId)===Number(p.id) || d.produtoNome===p.nome);
    console.log('registroDistribuicao (', regDist.length, 'registros):');
    regDist.forEach(d => console.log(`  rep="${d.representante}" qtd=${d.quantidade} data=${d.data} produtoId=${d.produtoId}`));
    const regDev = (estoque.registroDevolucoes||[]).filter(d => Number(d.produtoId)===Number(p.id) || d.produtoNome===p.nome);
    console.log('registroDevolucoes (', regDev.length, 'registros):');
    regDev.forEach(d => console.log(`  origem="${d.origem}" destino="${d.destino}" qtd=${d.quantidade} data=${d.data} produtoId=${d.produtoId}`));
    console.groupEnd();

    // --- vendas ---
    console.group('vendas nos registroVendas');
    const todasVendasProduto = (estoque.registroVendas||[]).filter(v => vendaMatchProduto(v, p));
    console.log('Total de registros com este produto (incluindo cancelados):', todasVendasProduto.length);
    const repsUnicos = [...new Set(todasVendasProduto.map(v => JSON.stringify({rep: v.representante, cancelado: !!v.cancelado})))];
    console.log('Representantes distintos nas vendas:', repsUnicos);
    const vendasDoRep = todasVendasProduto.filter(v => !v.cancelado && (v.representante||'').toUpperCase() === repUpper);
    console.log(`Vendas ativas com representante="${rep}" (case-insensitive):`, vendasDoRep.length);
    let vendidoRep = 0;
    vendasDoRep.forEach(v => {
        const qtd = vendaItemQtdParaProduto(v, p);
        vendidoRep += qtd;
        console.log(`  contrato=${v.contrato} rep="${v.representante}" qtd=${qtd}`);
    });
    console.log('Total vendido para', rep, ':', vendidoRep);
    console.groupEnd();

    // --- resultado ---
    const distribuido = distribKey ? (p.distribuicao[distribKey] || 0) : 0;
    console.log('RESULTADO → Distribuído:', distribuido, '| Vendido:', vendidoRep, '| Disponível:', distribuido - vendidoRep);
    console.groupEnd();
}
window.diagRep = diagRep;

// Verifica integridade do estoque: detecta divergências entre produto.vendas e registroVendas
function verificarIntegridadeEstoque() {
    const divergencias = [];
    (estoque.produtos || []).forEach(p => {
        (estoque.representantes || []).forEach(rep => {
            const repUpper = rep.toUpperCase();
            const vendidoRegistros = (estoque.registroVendas || []).reduce((s, v) => {
                if (v.cancelado) return s;
                if ((v.representante || '').toUpperCase() !== repUpper) return s;
                return s + vendaItemQtdParaProduto(v, p);
            }, 0);
            const vendidoCache = Number((p.vendas && p.vendas[rep]) || 0);
            if (vendidoCache !== vendidoRegistros) {
                divergencias.push({ produto: p.nome, rep, cache: vendidoCache, registros: vendidoRegistros });
            }
        });
    });

    if (divergencias.length === 0) {
        mostrarNotificacao('Integridade OK — nenhuma divergência encontrada.', 'success');
        return;
    }

    let html = `<div style="max-height:300px;overflow-y:auto;font-size:0.82rem">
        <p style="color:#dc2626;font-weight:600;margin-bottom:8px">${divergencias.length} divergência(s) encontrada(s):</p>
        <table style="width:100%;border-collapse:collapse">
        <tr style="background:#f1f5f9;font-weight:600"><td style="padding:4px 8px">Produto</td><td>Rep</td><td>Cache</td><td>Real</td></tr>`;
    divergencias.forEach(d => {
        html += `<tr style="border-top:1px solid #e2e8f0">
            <td style="padding:4px 8px">${d.produto}</td>
            <td>${d.rep}</td>
            <td style="color:#dc2626">${d.cache}</td>
            <td style="color:#15803d">${d.registros}</td>
        </tr>`;
    });
    html += '</table></div><p style="margin-top:8px;font-size:0.8rem;color:#64748b">Clique em Corrigir para reconstruir os agregados.</p>';

    const modal = document.getElementById('modalIntegridadeEstoque');
    if (modal) {
        const body = document.getElementById('corpoModalIntegridade') || modal.querySelector('.modal-body');
        if (body) body.innerHTML = html;
        modal.style.display = 'flex';
    } else {
        // Fallback: alert simples
        const linhas = divergencias.map(d => `${d.produto} / ${d.rep}: cache=${d.cache}, real=${d.registros}`).join('\n');
        if (confirm(`${divergencias.length} divergência(s):\n\n${linhas}\n\nDeseja corrigir agora?`)) {
            reconstruirVendasAPartirDeRegistros();
            salvarDados();
            mostrarNotificacao('Agregados reconstruídos com sucesso.', 'success');
        }
    }
}
window.verificarIntegridadeEstoque = verificarIntegridadeEstoque;

// =============================
// Firebase (inicialização e helpers)
// =============================
// Atualiza o indicador visual de status do Firestore (presente no header)
function updateFirestoreStatus(connected, lastSyncDate, message) {
    try {
        const el = document.getElementById('firestoreStatus');
        const dot = document.getElementById('fsDot');
        const text = document.getElementById('fsText');
        if (!el || !dot || !text) return;
        dot.classList.remove('fs-online', 'fs-offline', 'fs-warning', 'fs-saving');
        if (message && (message.includes('Salvando') || message.includes('aguardando'))) {
            dot.classList.add('fs-warning');
            text.textContent = message;
        } else if (connected) {
            dot.classList.add('fs-online');
            if (lastSyncDate) {
                const dt = (lastSyncDate instanceof Date) ? lastSyncDate : new Date(lastSyncDate);
                const hm = dt.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
                text.textContent = (message || 'Sincronizado') + ' • ' + hm;
            } else {
                text.textContent = message || 'Cloud: conectado';
            }
        } else {
            dot.classList.add('fs-offline');
            text.textContent = message || 'Cloud: desconectado';
        }
        // Banner sem login
        const banner = document.getElementById('bannerSemSync');
        if (banner) {
            const semLogin = message && message.includes('aguardando login');
            banner.style.display = semLogin ? 'flex' : 'none';
        }
    } catch (e) { /* ignore UI update errors */ }
}

// Exporta backup JSON local (1x por dia automaticamente)
function exportarBackupLocal(forcar) {
    try {
        const hoje = new Date().toISOString().split('T')[0];
        if (!forcar) {
            const ultimo = localStorage.getItem('_ultimoBackupLocal');
            if (ultimo === hoje) return;
        }
        const dados = JSON.stringify(estoque, null, 2);
        const blob = new Blob([dados], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `backup-estoque-${hoje}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        localStorage.setItem('_ultimoBackupLocal', hoje);
        if (forcar) mostrarNotificacao('Backup exportado: backup-estoque-' + hoje + '.json', 'success');
    } catch (e) {
        console.error('exportarBackupLocal falhou:', e);
    }
}
window.exportarBackupLocal = exportarBackupLocal;

// Exporta relatório de estoque por representante (Excel ou CSV)
function exportarRelatorioRepresentante(rep) {
    try {
        const reps = rep ? [rep] : (estoque.representantes || []).filter(r => r !== 'IMBEL');
        const rows = [];
        (estoque.produtos || []).forEach(p => {
            reps.forEach(r => {
                const repUpper = r.toUpperCase();
                const distribKey = p.distribuicao ? Object.keys(p.distribuicao).find(k => k.toUpperCase() === repUpper) : null;
                const distribuido = distribKey ? (p.distribuicao[distribKey] || 0) : 0;
                if (distribuido === 0) return;
                const vendido = (estoque.registroVendas || []).reduce((s, v) => {
                    if (v.cancelado) return s;
                    if ((v.representante || '').toUpperCase() !== repUpper) return s;
                    return s + vendaItemQtdParaProduto(v, p);
                }, 0);
                const disponivel = distribuido - vendido;
                rows.push({ Representante: r, Produto: p.nome, PN: p.pn || '', Distribuído: distribuido, Vendido: vendido, Disponível: disponivel });
            });
        });
        if (!rows.length) { mostrarNotificacao('Nenhum dado para exportar.', 'warning'); return; }
        const data = new Date().toISOString().split('T')[0];
        const filename = `relatorio-estoque-${rep || 'todos'}-${data}`;
        if (window.XLSX) {
            const ws = XLSX.utils.json_to_sheet(rows);
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, 'Estoque');
            XLSX.writeFile(wb, filename + '.xlsx');
        } else {
            const header = Object.keys(rows[0]).join(';');
            const csv = header + '\n' + rows.map(r => Object.values(r).join(';')).join('\n');
            const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a'); a.href = url; a.download = filename + '.csv';
            document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
        }
        mostrarNotificacao(`Relatório exportado: ${filename}`, 'success');
    } catch (e) { console.error('exportarRelatorioRepresentante falhou:', e); mostrarNotificacao('Erro ao exportar relatório.', 'error'); }
}
