        const nomeInner = isPeca
            ? `<span class="loj2-nome-peca">&#8627; ${_escapeHtml(prod.nome)}</span>`
            : `<span class="loj2-nome-prod">${_escapeHtml(prod.nome)}</span>${temPecas ? `<span id="${idSlot}"></span>` : ''}`;
